        "path": "baldurs-gate-3-trainer/Program.cs",
        "content": "using System;\nusing System.Diagnostics;\nusing System.Threading;\n\nnamespace BG3Trainer\n{\n    /// <summary>\n    /// Main entry point for the Baldur's Gate 3 Trainer.\n    /// Provides a console menu to enable/disable cheats via memory manipulation.\n    /// </summary>\n    internal class Program\n    {\n        private static bool _isRunning = true;\n        private static Process? _gameProcess;\n        private static MemoryManager? _memoryManager;\n\n        static void Main(string[] args)\n        {\n            Console.WriteLine(\"=== Baldur's Gate 3 Trainer v1.0 ===\");\n            Console.WriteLine(\"Make sure Baldur's Gate 3 is running.\");\n            Console.WriteLine();\n\n            // Attempt to attach to the game process\n            _gameProcess = Process.GetProcessesByName(\"bg3\").FirstOrDefault()\n                          ?? Process.GetProcessesByName(\"BaldursGate3\").FirstOrDefault();\n\n            if (_gameProcess == null)\n            {\n                Console.WriteLine(\"Error: Baldur's Gate 3 process not found. Start the game first.\");\n                Console.WriteLine(\"Press any key to exit...\");\n                Console.ReadKey();\n                return;\n            }\n\n            Console.WriteLine($\"Attached to process: {_gameProcess.ProcessName} (PID: {_gameProcess.Id})\");\n            _memoryManager = new MemoryManager(_gameProcess);\n\n            // Main menu loop\n            while (_isRunning)\n            {\n                Console.WriteLine();\n                Console.WriteLine(\"Available cheats:\");\n                Console.WriteLine(\"1 - Infinite Health\");\n                Console.WriteLine(\"2 - Infinite Spell Slots\");\n                Console.WriteLine(\"3 - Unlimited Gold\");\n                Console.WriteLine(\"4 - Set Movement Speed (x2)\");\n                Console.WriteLine(\"0 - Exit\");\n                Console.Write(\"Select option: \");\n\n                string? input = Console.ReadLine();\n                switch (input)\n                {\n                    case \"1\":\n                        ToggleInfiniteHealth();\n                        break;\n                    case \"2\":\n                        ToggleInfiniteSpellSlots();\n                        break;\n                    case \"3\":\n                        SetUnlimitedGold();\n                        break;\n                    case \"4\":\n                        SetMovementSpeed();\n                        break;\n                    case \"0\":\n                        _isRunning = false;\n                        break;\n                    default:\n                        Console.WriteLine(\"Invalid option.\");\n                        break;\n                }\n            }\n\n            Console.WriteLine(\"Trainer exiting. Goodbye!\");\n        }\n\n        /// <summary>\n        /// Toggles infinite health by patching the health decrement function.\n        /// </summary>\n        private static void ToggleInfiniteHealth()\n        {\n            if (_memoryManager == null) return;\n            // Example: NOP out the subtraction instruction at a known offset (placeholder)\n            // In a real trainer, you'd scan for the health address or use AOB.\n            _memoryManager.WriteBytes(0x12345678, new byte[] { 0x90, 0x90, 0x90 });\n            Console.WriteLine(\"Infinite Health toggled (NOP patch applied).\");\n        }\n\n        /// <summary>\n        /// Toggles infinite spell slots by freezing the spell slot counter.\n        /// </summary>\n        private static void ToggleInfiniteSpellSlots()\n        {\n            if (_memoryManager == null) return;\n            // Example: Write a high value to a static address (placeholder)\n            _memoryManager.WriteInt32(0x87654321, 999);\n            Console.WriteLine(\"Infinite Spell Slots activated (value set to 999).\");\n        }\n\n        /// <summary>\n        /// Sets gold to a large value.\n        /// </summary>\n        private static void SetUnlimitedGold()\n        {\n            if (_memoryManager == null) return;\n            // Example: Write to a known gold pointer (placeholder)\n            _memoryManager.WriteInt32(0x11223344, 999999);\n            Console.WriteLine(\"Gold set to 999,999.\");\n        }\n\n        /// <summary>\n        /// Patches movement speed multiplier.\n        /// </summary>\n        private static void SetMovementSpeed()\n        {\n            if (_memoryManager == null) return;\n            // Example: Write a float value for speed multiplier (placeholder)\n            _memoryManager.WriteFloat(0xAABBCCDD, 2.0f);\n            Console.WriteLine(\"Movement speed set to 2x.\");\n        }\n    }\n}\n"
    },
