        "path": "baldurs-gate-3-trainer/MemoryManager.cs",
        "content": "using System;\nusing System.Diagnostics;\nusing System.Runtime.InteropServices;\n\nnamespace BG3Trainer\n{\n    /// <summary>\n    /// Provides low-level memory operations for the target process.\n    /// Uses Windows kernel32.dll functions for ReadProcessMemory and WriteProcessMemory.\n    /// </summary>\n    public class MemoryManager\n    {\n        private readonly IntPtr _processHandle;\n        private readonly Process _targetProcess;\n\n        // Import required Windows API functions\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern IntPtr OpenProcess(uint dwDesiredAccess, bool bInheritHandle, int dwProcessId);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool ReadProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesRead);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool WriteProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesWritten);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool CloseHandle(IntPtr hObject);\n\n        private const uint PROCESS_VM_READ = 0x0010;\n        private const uint PROCESS_VM_WRITE = 0x0020;\n        private const uint PROCESS_VM_OPERATION = 0x0008;\n        private const uint PROCESS_QUERY_INFORMATION = 0x0400;\n\n        /// <summary>\n        /// Initializes a new MemoryManager for the given process.\n        /// </summary>\n        /// <param name=\"process\">The target process (must be running).</param>\n        public MemoryManager(Process process)\n        {\n            _targetProcess = process ?? throw new ArgumentNullException(nameof(process));\n            uint accessFlags = PROCESS_VM_READ | PROCESS_VM_WRITE | PROCESS_VM_OPERATION | PROCESS_QUERY_INFORMATION;\n            _processHandle = OpenProcess(accessFlags, false, process.Id);\n\n            if (_processHandle == IntPtr.Zero)\n            {\n                throw new InvalidOperationException($\"Failed to open process {process.ProcessName}. Error: {Marshal.GetLastWin32Error()}\");\n            }\n        }\n\n        /// <summary>\n        /// Reads a byte array from the target process memory.\n        /// </summary>\n        /// <param name=\"address\">The base address to read from.</param>\n        /// <param name=\"size\">Number of bytes to read.</param>\n        /// <returns>Byte array of read data.</returns>\n        public byte[] ReadBytes(IntPtr address, int size)\n        {\n            byte[] buffer = new byte[size];\n            if (!ReadProcessMemory(_processHandle, address, buffer, size, out int bytesRead))\n            {\n                throw new InvalidOperationException($\"Failed to read memory at 0x{address.ToInt64():X}. Error: {Marshal.GetLastWin32Error()}\");\n            }\n            if (bytesRead != size)\n            {\n                throw new InvalidOperationException($\"Read {bytesRead} bytes, expected {size}.\");\n            }\n            return buffer;\n        }\n\n        /// <summary>\n        /// Writes a byte array to the target process memory.\n        /// </summary>\n        /// <param name=\"address\">The base address to write to.</param>\n        /// <param name=\"data\">Byte array to write.</param>\n        public void WriteBytes(IntPtr address, byte[] data)\n        {\n            if (!WriteProcessMemory(_processHandle, address, data, data.Length, out int bytesWritten))\n            {\n                throw new InvalidOperationException($\"Failed to write memory at 0x{address.ToInt64():X}. Error: {Marshal.GetLastWin32Error()}\");\n            }\n            if (bytesWritten != data.Length)\n            {\n                throw new InvalidOperationException($\"Wrote {bytesWritten} bytes, expected {data.Length}.\");\n            }\n        }\n\n        /// <summary>\n        /// Reads a 32-bit integer from the target process memory.\n        /// </summary>\n        /// <param name=\"address\">The address to read from.</param>\n        /// <returns>Integer value.</returns>\n        public int ReadInt32(IntPtr address)\n        {\n            byte[] data = ReadBytes(address, 4);\n            return BitConverter.ToInt32(data, 0);\n        }\n\n        /// <summary>\n        /// Writes a 32-bit integer to the target process memory.\n        /// </summary>\n        /// <param name=\"address\">The address to write to.</param>\n        /// <param name=\"value\">Integer value to write.</param>\n        public void WriteInt32(IntPtr address, int value)\n        {\n            byte[] data = BitConverter.GetBytes(value);\n            WriteBytes(address, data);\n        }\n\n        /// <summary>\n        /// Reads a 32-bit float from the target process memory.\n        /// </summary>\n        /// <param name=\"address\">The address to read from.</param>\n        /// <returns>Float value.</returns>\n        public float ReadFloat(IntPtr address)\n        {\n            byte[] data = ReadBytes(address, 4);\n            return BitConverter.ToSingle(data, 0);\n        }\n\n        /// <summary>\n        /// Writes a 32-bit float to the target process memory.\n        /// </summary>\n        /// <param name=\"address\">The address to write to.</param>\n        /// <param name=\"value\">Float value to write.</param>\n        public void WriteFloat(IntPtr address, float value)\n        {\n            byte[] data = BitConverter.GetBytes(value);\n            WriteBytes(address, data);\n        }\n\n        /// <summary>\n        /// Overload for convenience using long address (cast to IntPtr).\n        /// </summary>\n        public void WriteBytes(long address, byte[] data) => WriteBytes((IntPtr)address, data);\n\n        /// <summary>\n        /// Overload for convenience using long address.\n        /// </summary>\n        public void WriteInt32(long address, int value) => WriteInt32((IntPtr)address, value);\n\n        /// <summary>\n        /// Overload for convenience using long address.\n        /// </summary>\n        public void WriteFloat(long address, float value) => WriteFloat((IntPtr)address, value);\n\n        /// <summary>\n        /// Cleans up the process handle.\n        /// </summary>\n        public void Dispose()\n        {\n            if (_processHandle != IntPtr.Zero)\n            {\n                CloseHandle(_processHandle);\n            }\n        }\n    }\n}\n"
    },
