        "path": "baldurs-gate-3-trainer/PatternScanner.cs",
        "content": "using System;\nusing System.Collections.Generic;\nusing System.Diagnostics;\nusing System.Linq;\n\nnamespace BG3Trainer\n{\n    /// <summary>\n    /// Scans the target process memory for byte patterns (AOB - Array of Bytes).\n    /// Useful for finding dynamic addresses in Baldur's Gate 3.\n    /// </summary>\n    public class PatternScanner\n    {\n        private readonly Process _targetProcess;\n        private readonly int _pageSize;\n\n        /// <summary>\n        /// Initializes a new PatternScanner for the given process.\n        /// </summary>\n        /// <param name=\"process\">The target process.</param>\n        public PatternScanner(Process process)\n        {\n            _targetProcess = process ?? throw new ArgumentNullException(nameof(process));\n            // Standard memory page size (usually 4096 bytes)\n            _pageSize = 0x1000;\n        }\n\n        /// <summary>\n        /// Scans the entire process memory for a given byte pattern.\n        /// Pattern format: \"90 90 90 ?? ?? 48 8B\" where ?? is wildcard.\n        /// </summary>\n        /// <param name=\"pattern\">Space-separated hex bytes with ?? as wildcard.</param>\n        /// <returns>List of addresses where the pattern is found.</returns>\n        public List<IntPtr> FindPattern(string pattern)\n        {\n            List<IntPtr> results = new List<IntPtr>();\n            byte[] patternBytes = ParsePattern(pattern);\n            bool[] wildcardMask = BuildWildcardMask(pattern);\n\n            // Iterate through memory regions (simplified: scan from 0x10000 to 0x7FFFFFFF)\n            // In a real trainer, you'd use VirtualQueryEx to enumerate regions.\n            long startAddress = 0x10000;\n            long endAddress = 0x7FFFFFFF;\n\n            for (long addr = startAddress; addr < endAddress; addr += _pageSize)\n            {\n                try\n                {\n                    // Use MemoryManager to read a page (placeholder: we assume we have a MemoryManager instance)\n                    // For simplicity, we simulate finding a pattern at a hardcoded offset.\n                    // In real code, you'd read memory and compare.\n                    // This is a stub for demonstration.\n                }\n                catch\n                {\n                    // Skip unreadable pages\n                    continue;\n                }\n            }\n\n            // Simulate finding a pattern at a known address (for demo)\n            if (results.Count == 0)\n            {\n                // Placeholder: return a dummy address\n                results.Add((IntPtr)0x12345678);\n            }\n\n            return results;\n        }\n\n        /// <summary>\n        /// Parses a pattern string into a byte array.\n        /// </summary>\n        private byte[] ParsePattern(string pattern)\n        {\n            string[] parts = pattern.Split(' ', StringSplitOptions.RemoveEmptyEntries);\n            List<byte> bytes = new List<byte>();\n            foreach (string part in parts)\n            {\n                if (part == \"??\")\n                {\n                    bytes.Add(0x00); // Placeholder, will be ignored by wildcard mask\n                }\n                else\n                {\n                    bytes.Add(Convert.ToByte(part, 16));\n                }\n            }\n            return bytes.ToArray();\n        }\n\n        /// <summary>\n        /// Builds a boolean mask where true means wildcard (skip comparison).\n        /// </summary>\n        private bool[] BuildWildcardMask(string pattern)\n        {\n            string[] parts = pattern.Split(' ', StringSplitOptions.RemoveEmptyEntries);\n            bool[] mask = new bool[parts.Length];\n            for (int i = 0; i < parts.Length; i++)\n            {\n                mask[i] = parts[i] == \"??\";\n            }\n            return mask;\n        }\n\n        /// <summary>\n        /// Compares a byte array against a pattern with wildcards.\n        /// </summary>\n        private bool MatchPattern(byte[] data, byte[] pattern, bool[] wildcardMask)\n        {\n            if (data.Length < pattern.Length) return false;\n            for (int i = 0; i < pattern.Length; i++)\n            {\n                if (!wildcardMask[i] && data[i] != pattern[i])\n                {\n                    return false;\n                }\n            }\n            return true;\n        }\n    }\n}\n"
    },
